class Solution {
    fun sortArray(nums: IntArray): IntArray {

        quickSort(nums, 0, nums.size - 1)
        return nums
    }

    fun quickSort(nums: IntArray, left: Int, right: Int)
    {
        if(left &lt; right)
        {
            val partitionIdx = partition(nums, left, right)

            quickSort(nums, left, partitionIdx - 1) // makes it to be DFS
            quickSort(nums, partitionIdx + 1, right)
        }
    }

    fun partition(nums: IntArray, left: Int, right: Int) : Int{
        val pivot = nums[left]
        var l = left + 1 // pointer 1
        var r = right // pointer 2

        var active = true
        while(active){

            while(l &lt;= r &amp;&amp; nums[l] &lt;= pivot)
            {
                l++
            }

            while(l &lt;= r &amp;&amp; nums[r] &gt;= pivot)
            {
                r--
            }

            if(l &gt; r)
            {
                active = false
            }
            else{
                val temp = nums[l]
                nums[l] = nums[r]
                nums[r] = temp
            }
        }

        val temp = nums[left]
        nums[left] = nums[r]
        nums[r] = temp

        return r
    }
}
